import math
import pytest
import yaml
from pathlib import Path
import sys

# Add parent directory to path to import modules
sys.path.insert(0, str(Path(__file__).parent.parent))

import graph
from astar import a_star


def _manhattan_distance(pos_map):
    """Create a heuristic function using Manhattan distance."""
    def heuristic(node, goal=None):
        if goal is None:
            return 0
        node_pos = pos_map.get(node.element(), (0, 0))
        goal_pos = pos_map.get(goal.element(), (0, 0))
        return abs(node_pos[0] - goal_pos[0]) + abs(node_pos[1] - goal_pos[1])
    return heuristic


def _euclidean_distance(pos_map):
    """Create a heuristic function using Euclidean distance."""
    def heuristic(node, goal=None):
        if goal is None:
            return 0
        node_pos = pos_map.get(node.element(), (0, 0))
        goal_pos = pos_map.get(goal.element(), (0, 0))
        dx = node_pos[0] - goal_pos[0]
        dy = node_pos[1] - goal_pos[1]
        return math.sqrt(dx * dx + dy * dy)
    return heuristic


def _load_fixture(fixture_name):
    """Load a YAML fixture file."""
    fixture_path = Path(__file__).parent / 'fixtures' / f'{fixture_name}.yaml'
    with open(fixture_path) as f:
        return yaml.safe_load(f)


def _build_graph(fixture):
    """Build a Graph object from a fixture dictionary."""
    edges = fixture['edges']
    is_directed = fixture.get('is_directed', False)
    g, _ = graph.create_graph(edges, is_directed=is_directed)
    return g


class TestAStarSimplePath:
    """Tests on simple linear path graph."""

    @pytest.fixture
    def fixture(self):
        return _load_fixture('simple_path')

    @pytest.fixture
    def test_graph(self, fixture):
        return _build_graph(fixture)

    def test_simple_path_to_end(self, test_graph, fixture):
        """Test finding path from start to end of chain."""
        start = test_graph.get_vertex('a')
        goal = test_graph.get_vertex('d')
        pos_map = fixture['node_positions']
        heuristic = _euclidean_distance(pos_map)

        path, length = a_star(test_graph, start, goal, heuristic)

        assert path == ['a', 'b', 'c', 'd']
        assert length == 3

    def test_simple_path_to_middle(self, test_graph, fixture):
        """Test finding path from start to middle of chain."""
        start = test_graph.get_vertex('a')
        goal = test_graph.get_vertex('b')
        pos_map = fixture['node_positions']
        heuristic = _euclidean_distance(pos_map)

        path, length = a_star(test_graph, start, goal, heuristic)

        assert path == ['a', 'b']
        assert length == 1

    def test_start_equals_goal(self, test_graph, fixture):
        """Test when start and goal are the same node."""
        start = test_graph.get_vertex('a')
        goal = test_graph.get_vertex('a')
        pos_map = fixture['node_positions']
        heuristic = _euclidean_distance(pos_map)

        path, length = a_star(test_graph, start, goal, heuristic)

        assert path == ['a']
        assert length == 0


class TestAStarGrid:
    """Tests on 2x2 grid graph."""

    @pytest.fixture
    def fixture(self):
        return _load_fixture('grid_2x2')

    @pytest.fixture
    def test_graph(self, fixture):
        return _build_graph(fixture)

    def test_grid_diagonal_path(self, test_graph, fixture):
        """Test finding diagonal path in grid."""
        start = test_graph.get_vertex('a')
        goal = test_graph.get_vertex('d')
        pos_map = fixture['node_positions']
        heuristic = _manhattan_distance(pos_map)

        path, length = a_star(test_graph, start, goal, heuristic)

        assert len(path) == 3
        assert path[0] == 'a'
        assert path[-1] == 'd'
        assert length == 2

    def test_grid_adjacent_nodes(self, test_graph, fixture):
        """Test path between adjacent nodes in grid."""
        start = test_graph.get_vertex('a')
        goal = test_graph.get_vertex('c')
        pos_map = fixture['node_positions']
        heuristic = _euclidean_distance(pos_map)

        path, length = a_star(test_graph, start, goal, heuristic)

        assert path == ['a', 'c']
        assert length == 1


class TestAStarDisconnected:
    """Tests on disconnected graph components."""

    @pytest.fixture
    def fixture(self):
        return _load_fixture('disconnected')

    @pytest.fixture
    def test_graph(self, fixture):
        return _build_graph(fixture)

    def test_reachable_path_in_component(self, test_graph, fixture):
        """Test finding path within a connected component."""
        start = test_graph.get_vertex('a')
        goal = test_graph.get_vertex('c')
        pos_map = fixture['node_positions']
        heuristic = _manhattan_distance(pos_map)

        path, length = a_star(test_graph, start, goal, heuristic)

        assert path == ['a', 'b', 'c']
        assert length == 2

    def test_unreachable_from_different_component(self, test_graph, fixture):
        """Test that unreachable nodes return empty path and infinite length."""
        start = test_graph.get_vertex('a')
        goal = test_graph.get_vertex('d')
        pos_map = fixture['node_positions']
        heuristic = _manhattan_distance(pos_map)

        path, length = a_star(test_graph, start, goal, heuristic)

        assert path == []
        assert length == float('inf')

    def test_path_in_second_component(self, test_graph, fixture):
        """Test finding path in second disconnected component."""
        start = test_graph.get_vertex('d')
        goal = test_graph.get_vertex('f')
        pos_map = fixture['node_positions']
        heuristic = _euclidean_distance(pos_map)

        path, length = a_star(test_graph, start, goal, heuristic)

        assert path == ['d', 'e', 'f']
        assert length == 2


class TestAStarHeuristics:
    """Tests behavior with different heuristics."""

    @pytest.fixture
    def fixture(self):
        return _load_fixture('grid_2x2')

    @pytest.fixture
    def test_graph(self, fixture):
        return _build_graph(fixture)

    def test_with_zero_heuristic(self, test_graph):
        """Test that zero heuristic (Dijkstra-like) still finds path."""
        start = test_graph.get_vertex('a')
        goal = test_graph.get_vertex('d')

        path, length = a_star(test_graph, start, goal, lambda n: 0)

        assert path[0] == 'a'
        assert path[-1] == 'd'
        assert length == 2

    def test_with_perfect_heuristic(self, test_graph, fixture):
        """Test with perfect heuristic (exact distance)."""
        start = test_graph.get_vertex('a')
        goal = test_graph.get_vertex('d')
        pos_map = fixture['node_positions']

        def perfect_heuristic(node):
            return _manhattan_distance(pos_map)(node, goal)

        path, length = a_star(test_graph, start, goal, perfect_heuristic)

        assert path[0] == 'a'
        assert path[-1] == 'd'
        assert length == 2

